#include <stdio.h>
#include <stdbool.h>
#include <string.h>

#define MAX_SIZE 1001

bool isBalanced(char str[]) {
    int stack[MAX_SIZE];
    int top = -1;
    for (int i = 0; i < strlen(str); i++) {
        if (str[i] == '(') {
            stack[++top] = '(';
        } else if (str[i] == ')') {
            if (top == -1) return false;
            top--;
        }
    }
    return top == -1;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        char str[MAX_SIZE];
        scanf("%1000s", str);
        printf("%s : %s\n", str, isBalanced(str) ? "true" : "false");
    }
    return 0;
}

